const issueId = $json.body?.issue?.id;
const statusId = $json.body?.issue?.fields?.status?.id;
const ts = $json.body?.timestamp;

const key = (issueId && statusId && ts)
  ? `jira:auto:${issueId}:${statusId}:${ts}`
  : `fallback:${$json.headers?.["x-b3-traceid"] || "no-trace"}:${$json.headers?.["x-b3-spanid"] || "no-span"}`;

const data = $getWorkflowStaticData('global');
data.seen = data.seen || {};

const now = Date.now();
const maxAgeMs = 7 * 24 * 60 * 60 * 1000;
for (const [k, v] of Object.entries(data.seen)) {
  if ((v || 0) < now - maxAgeMs) delete data.seen[k];
}

if (data.seen[key]) {
  return [{ json: { ...$json, idempotency: { ok: false, duplicate: true, key } } }];
}

data.seen[key] = now;
return [{ json: { ...$json, idempotency: { ok: true, duplicate: false, key } } }];

// Project key → working directory map (add new products here)
const PROJECT_DIRS = {
  CER: "{{DEFAULT_WORKING_DIR}}",
  EOS: "{{DEFAULT_WORKING_DIR}}",
  WMS: "{{DEFAULT_WORKING_DIR}}"
};
const DEFAULT_DIR = "{{DEFAULT_WORKING_DIR}}";

const projectKey = $json.body?.issue?.fields?.project?.key || "";
const workingDir = PROJECT_DIRS[projectKey] || DEFAULT_DIR;

const eventType = String($json.headers?.["x-event-type"] || "")
  .trim()
  .toLowerCase();

const summary = $json.body?.issue?.fields?.summary || "";
const issueType = $json.body?.issue?.fields?.issuetype?.name || "";
const labels = ($json.body?.issue?.fields?.labels || []).map(l => typeof l === 'string' ? l : l.name || '');

// Agent Teams handles implement and code-review inline (planner spawns teammates)
const AGENT_TEAMS_HANDLED = ["implement", "code-review"];
if (AGENT_TEAMS_HANDLED.includes(eventType)) {
  throw new Error(`Event "${eventType}" is handled by Agent Teams \u2014 skipping duplicate dispatch. Disable Jira automation rules 1002/1003 to stop these events.`);
}

const isMarketingTask = summary.startsWith("[Marketing]");
const isBugTask = issueType.toLowerCase() === "bug";
const isSecurityFix = labels.includes('security-fix') || labels.includes('security-vulnerability');
const needsPipeline = labels.includes('needs-requirements') || labels.includes('needs-ux-design');
// Agent-created bugs already have a root-cause note — skip triage and go straight to bug-fix pipeline
const isAgentCreatedBug = labels.includes('agent-created-bug') || labels.includes('agent:engineer-planner');

let agent;
let usePipeline = false;
let pipelineType = null;

if (eventType) {
  agent =
    eventType === "plan" ? "engineer-planner"
    : eventType === "acceptance-review" ? "product-manager"
    : eventType === "bug-triage" ? "bug-triage"
    : eventType === "bug-created" ? "bug-triage"
    : eventType === "marketing" ? "marketing"
    : null;
} else {
  if (isMarketingTask) {
    agent = "marketing";
  } else if (isBugTask) {
    if (isSecurityFix) {
      usePipeline = true;
      pipelineType = "security-fix";
    } else if (isAgentCreatedBug) {
      // Agent-created bugs already have root-cause analysis — bypass triage and go directly to bug-fix pipeline
      usePipeline = true;
      pipelineType = "bug-fix";
    } else {
      agent = "bug-triage";
    }
  } else {
    // Default: all Stories/Tasks go through new-feature pipeline (no label required)
    usePipeline = true;
    pipelineType = "new-feature";
  }
}

if (!usePipeline && !agent) throw new Error(`Cannot determine agent for event: ${eventType}`);

if (usePipeline) {
  return [{
    json: {
      usePipeline: true,
      pipeline: {
        issueKey: $json.body.issue.key,
        pipelineType,
        labels,
        workingDir
      }
    }
  }];
}

return [{
  json: {
    usePipeline: false,
    job: {
      agent,
      issueKey: $json.body.issue.key,
      summary,
      description: $json.body.issue.fields.description,
      projectKey,
      issueType,
      triggeredAt: $json.body.timestamp,
      workingDir,
      isMarketingTask
    }
  }
}];
